function generateOfficers(count) {
  return Array.from({ length: count }, (_, i) => ({
    id: `OFF-${String(i + 101).padStart(3, "0")}`,
    firstName: rand(PEOPLE_FIRST),
    lastName: rand(PEOPLE_LAST),
    badge: `B${randInt(1000, 9999)}`,
    status: rand(OFFICER_STATUSES),
    phone: `(${randInt(200, 999)}) ${randInt(200, 999)}-${randInt(1000, 9999)}`,
    radio: `CH-${randInt(1, 12)}`,
    vehicle: `Unit ${randInt(1, 20)}`,
    zone: `Zone ${randInt(1, 6)}`,
    activeCalls: randInt(0, 3),
    shiftStart: `${randInt(5, 9)}:00 AM`,
    shiftEnd: `${randInt(3, 7)}:00 PM`,
  }));
}

function generateCalls(count, officers) {
  const timeSlots = [];
  for (let h = 6; h <= 22; h++) {
    for (let m = 0; m < 60; m += 15) {
      timeSlots.push(`${h > 12 ? h - 12 : h}:${String(m).padStart(2, "0")} ${h >= 12 ? "PM" : "AM"}`);
    }
  }
  const PARTY_ROLES = ["Caller","Victim","Complainant","Witness","Owner"];
  return Array.from({ length: count }, (_, i) => {
    const status = rand(CALL_STATUSES);
    const numOfficers = status !== "Pending" && status !== "Cancelled" ? randInt(1, 2) : 0;
    const assigned = [];
    for (let o = 0; o < numOfficers; o++) {
      const off = rand(officers);
      if (!assigned.find((a) => a.id === off.id)) assigned.push({ id: off.id, name: `${off.firstName} ${off.lastName}`, vehicle: off.vehicle, badge: off.badge });
    }
    return {
      id: `C-${String(i + 5001).padStart(5, "0")}`,
      type: rand(CALL_TYPES),
      priority: rand(CALL_PRIORITIES),
      status,
      caller: `${rand(PEOPLE_FIRST)} ${rand(PEOPLE_LAST)}`,
      callerPhone: `(${randInt(200, 999)}) ${randInt(200, 999)}-${randInt(1000, 9999)}`,
      address: `${randInt(100, 9999)} ${rand(STREETS)}`,
      city: rand(CITIES),
      description: [
        "Caller reports a stray dog wandering near the school.",
        "Neighbor concerned about neglected animals at residence.",
        "Report of aggressive dog loose in the neighborhood.",
        "Cat stuck on the roof of a two-story building.",
        "Multiple animals heard barking excessively at all hours.",
        "Caller found an injured raccoon in their backyard.",
        "Dog left in vehicle in a parking lot on a hot day.",
        "Horses escaped from pasture onto the highway.",
        "Caller witnessed someone hitting a dog in the park.",
        "Abandoned kittens found behind the grocery store.",
        "Aggressive rooster chasing pedestrians on the sidewalk.",
        "Caller reports possible puppy mill at nearby property.",
      ][i % 12],
      dateReported: randDate(14),
      timeReported: rand(timeSlots),
      assignedOfficers: assigned,
      assignedOfficer: assigned[0]?.name || null,
      assignedOfficerId: assigned[0]?.id || null,
      assignedVehicle: assigned[0]?.vehicle || null,
      responseNotes: status === "Resolved" ? rand(["Animal secured and transported to shelter.","Owner contacted and issued a warning.","Animal returned to owner, no further action.","Referred to law enforcement for investigation.","Warning citation issued. Follow-up scheduled."]) : "",
      animalInvolved: rand(["Dog","Cat","Dog","Cat","Unknown","Multiple","Livestock","Wildlife"]),
      animalDescription: `${rand(COLORS)} ${rand([...BREEDS_DOG.slice(0,5), ...BREEDS_CAT.slice(0,3), "Mixed Breed", "Unknown"])}`,
      involvedParties: [
        { id: `IP-${genId()}`, role: "Caller", name: `${rand(PEOPLE_FIRST)} ${rand(PEOPLE_LAST)}`, phone: `(${randInt(200, 999)}) ${randInt(200, 999)}-${randInt(1000, 9999)}`, address: "", statement: "" },
      ],
      linkedCitations: [],
    };
  });
}

