const rand = (arr) => arr[Math.floor(Math.random() * arr.length)];
const randInt = (min, max) => Math.floor(Math.random() * (max - min + 1)) + min;
const randDate = (daysBack) => {
  const d = new Date();
  d.setDate(d.getDate() - randInt(0, daysBack));
  return d.toISOString().split("T")[0];
};
const genId = () => Math.random().toString(36).substring(2, 9).toUpperCase();

function generateAnimals(count) {
  return Array.from({ length: count }, (_, i) => {
    const species = Math.random() > 0.45 ? "Dog" : "Cat";
    const isMale = Math.random() > 0.5;
    const status = rand(STATUSES.filter((s) => s !== "Euthanized"));
    const intakeDate = randDate(180);
    return {
      id: `A-${String(i + 1001).padStart(5, "0")}`,
      name: rand(species === "Dog" ? NAMES_DOG : NAMES_CAT),
      species,
      breed: rand(species === "Dog" ? BREEDS_DOG : BREEDS_CAT),
      color: rand(COLORS),
      sex: isMale ? "Male" : "Female",
      age: `${randInt(0, 12)}y ${randInt(0, 11)}m`,
      weight: species === "Dog" ? `${randInt(8, 90)} lbs` : `${randInt(4, 18)} lbs`,
      status,
      intakeType: rand(INTAKE_TYPES),
      intakeDate,
      kennel: Math.random() > 0.3 ? rand(KENNEL_LABELS) : "Unassigned",
      microchip: Math.random() > 0.3 ? `9${randInt(10, 99)}${randInt(1000000, 9999999)}` : "",
      fixed: Math.random() > 0.35,
      notes: [],
      pendingAdopter: status === "Pending" ? { name: `${rand(PEOPLE_FIRST)} ${rand(PEOPLE_LAST)}`, phone: `(${randInt(200, 999)}) ${randInt(200, 999)}-${randInt(1000, 9999)}`, email: `${rand(PEOPLE_FIRST).toLowerCase()}${randInt(1, 50)}@email.com`, date: randDate(14) } : null,
      attachedPeople: [],
      attachedCalls: [],
      euthanasia: null,
    };
  });
}

let _nextPersonNum = 1001;
function generatePeople(count) {
  const states = ["GA","GA","GA","AL","FL","SC","TN"];
  const cities = ["Covington","Conyers","Oxford","Monroe","Loganville","Social Circle","Porterdale","Mansfield"];
  return Array.from({ length: count }, (_, i) => ({
    id: `P-${genId()}`,
    pid: `PID-${String(_nextPersonNum++).padStart(5, "0")}`,
    firstName: rand(PEOPLE_FIRST),
    lastName: rand(PEOPLE_LAST),
    role: rand(["Adopter","Volunteer","Foster Parent","Donor","Staff"]),
    phone: `(${randInt(200, 999)}) ${randInt(200, 999)}-${randInt(1000, 9999)}`,
    email: `${rand(PEOPLE_FIRST).toLowerCase()}${randInt(1, 99)}@email.com`,
    address: `${randInt(100, 9999)} ${rand(["Oak","Elm","Maple","Pine","Cedar"])} ${rand(["St","Ave","Dr","Ln","Ct"])}`,
    city: rand(cities),
    state: rand(states),
    zip: `${randInt(30000, 31999)}`,
    idType: rand(["Driver's License","State ID","Passport","Military ID",""]),
    idNumber: Math.random() > 0.3 ? `${randInt(100000000, 999999999)}` : "",
    idState: rand(states),
    idExpiration: Math.random() > 0.3 ? randDate(-730) : "",
    dateAdded: randDate(365),
    notes: [],
  }));
}

function generateMedical(animals) {
  const records = [];
  animals.forEach((a) => {
    const numRecords = randInt(0, 4);
    for (let j = 0; j < numRecords; j++) {
      records.push({
        id: `M-${genId()}`,
        animalId: a.id,
        animalName: a.name,
        type: rand(MEDICAL_TYPES),
        description: rand(MEDICAL_TYPES) === "Vaccination" ? rand(VACC_NAMES) : `${rand(MEDICAL_TYPES)} procedure`,
        date: randDate(120),
        vet: `Dr. ${rand(PEOPLE_LAST)}`,
        cost: `$${randInt(15, 500)}`,
        nextDue: Math.random() > 0.5 ? randDate(-60) : "",
      });
    }
  });
  return records;
}

